patch:
--- a/alu_32bit.v
+++ b/alu_32bit.v
@@ -1,18 +1,18 @@
 module alu_32bit(
   input [31:0] operand_x, operand_y,
   input [3:0] opcode,
   output reg [31:0] result
 );

-  always @(operand_x or operand_y) begin
+  always @(*) begin
     case(opcode)
       4'h0: result = operand_x + operand_y;
       4'h1: result = operand_x - operand_y;
       4'h2: result = operand_x & operand_y;
       4'h3: result = operand_x | operand_y;
       4'h4: result = operand_x ^ operand_y;
       4'h5: result = ~operand_x;
       4'h6: result = operand_x << 1;
       4'h7: result = operand_x >> 1;
-      default: result = 32'h00000000;
+      default: result = 32'h00000000;
     endcase
   end

 endmodule

before_code:
module alu_32bit(
  input [31:0] operand_x, operand_y,
  input [3:0] opcode,
  output reg [31:0] result
);

  always @(operand_x or operand_y) begin
    case(opcode)
      4'h0: result = operand_x + operand_y;
      4'h1: result = operand_x - operand_y;
      4'h2: result = operand_x & operand_y;
      4'h3: result = operand_x | operand_y;
      4'h4: result = operand_x ^ operand_y;
      4'h5: result = ~operand_x;
      4'h6: result = operand_x << 1;
      4'h7: result = operand_x >> 1;
      default: result = 32'h00000000;
    endcase
  end

endmodule

after_code:
module alu_32bit(
  input [31:0] operand_x, operand_y,
  input [3:0] opcode,
  output reg [31:0] result
);

  always @(*) begin
    case(opcode)
      4'h0: result = operand_x + operand_y;
      4'h1: result = operand_x - operand_y;
      4'h2: result = operand_x & operand_y;
      4'h3: result = operand_x | operand_y;
      4'h4: result = operand_x ^ operand_y;
      4'h5: result = ~operand_x;
      4'h6: result = operand_x << 1;
      4'h7: result = operand_x >> 1;
      default: result = 32'h00000000;
    endcase
  end

endmodule
